bash_commands.command:
node -e "
const pluginNamePattern = /^(@[\w-]+\/)?nodebb-(theme|plugin|widget|rewards)-[\w-]+$/;
const testCases = [
  { id: '\t\nnodebb-plugin', expected: false },
  { id: 'notaplugin', expected: false },
  { id: 'nodebb-plugin-test', expected: true },
  { id: '@nodebb/nodebb-plugin-test', expected: true },
];
testCases.forEach(({ id, expected }) => {
  const result = pluginNamePattern.test(id);
  const status = result === expected ? '✓' : '✗';
  console.log(\`\${status} '\${id}' => \${result} (expected \${expected})\`);
});
"

code_changes.new_string:
Plugins.toggleInstall = async function (id, version) {
	if (!pluginNamePattern.test(id)) {
		throw new Error('[[error:invalid-plugin-id]]');
	}
	pubsub.publish('plugins:toggleInstall', { hostname: os.hostname(), id: id, version: version });
	return await toggleInstall(id, version);
};

